**(b)** Method overriding occurs when a Sub Class provides a new implementation for a method inherited from the Super Class.

```cpp
#include <iostream>
using namespace std;

class Shape {                          // SUPER CLASS
public:
    virtual void draw() {              // 'virtual' enables polymorphism
        cout << "Drawing a generic shape." << endl;
    }
};

class Circle : public Shape {          // SUB CLASS
public:
    void draw() override {             // OVERRIDE keyword for safety
        cout << "Drawing a circle." << endl;
    }
};

int main() {
    Shape* s = new Circle();           // Upcasting (Circle IS-A Shape)
    s->draw();                         // Calls Circle's draw() due to virtual dispatch
    delete s;
    return 0;
}
```

**Output:**

```
Drawing a circle.
```

